const bobX = cx + length * Math.sin(angle);
const bobY = cy + length * Math.cos(angle);

for (let i = 0; i < 12; i++) {
  const pastAngle = maxAngle * Math.cos((p - (i + 1) * 0.015) * Math.PI * 3);
  const px = cx + length * Math.sin(pastAngle);
  const py = cy + length * Math.cos(pastAngle);
  const alpha = 0.12 - i * 0.008;
  if (alpha > 0) {
    const trail = fill('rgba(59,130,246,' + alpha + ')');
    canvas.drawCircle(px, py, 20 - i, trail);
  }
}

canvas.drawLine(cx - 80, cy, cx + 80, cy, stroke('#334155', 4));
