canvas.drawCircle(cx, cy, 6, fill('#64748b'));

const arcPath = new CK.Path();
const steps = 40;
for (let i = 0; i <= steps; i++) {
  const a = -maxAngle + 2 * maxAngle * i / steps;
  const x = cx + length * Math.sin(a);
  const y = cy + length * Math.cos(a);
