const CK = ctx.CanvasKit;
const canvas = ctx.getCanvas();
const p = ctx.currentFrame / ctx.sceneFrames;

function fill(color) {
  const paint = new CK.Paint();
  paint.setStyle(CK.PaintStyle.Fill);
  paint.setColor(CK.parseColorString(color));
  paint.setAntiAlias(true);
  return paint;
}
function stroke(color, width) {
  const paint = new CK.Paint();
  paint.setStyle(CK.PaintStyle.Stroke);
  paint.setColor(CK.parseColorString(color));
  paint.setStrokeWidth(width);
  paint.setAntiAlias(true);
  return paint;
}

canvas.clear(CK.parseColorString('#eff6ff'));

const cx = 250, cy = 20;
const length = 200;
const maxAngle = 25 * Math.PI / 180;
const swingAngle = maxAngle * Math.cos(p * Math.PI * 3);
const rotationAngle = p * Math.PI * 0.5;

const bobX = cx + length * Math.sin(swingAngle) * Math.cos(rotationAngle);
const bobY = cy + length * Math.cos(swingAngle);

canvas.drawLine(cx - 40, cy, cx + 40, cy, stroke('#94a3b8', 4));
canvas.drawLine(cx, cy, bobX, bobY, stroke('#64748b', 2));
canvas.drawCircle(bobX, bobY, 14, fill('#1e40af'));
canvas.drawCircle(cx, cy, 5, fill('#94a3b8'));

const trailPath = new CK.Path();
for (let i = 0; i <= 60; i++) {
  const a = (i / 60) * Math.PI * 2;
  const r = 120;
  const x = cx + r * Math.cos(a);
  const y = 160 + r * Math.sin(a) * 0.3;
  if (i === 0) trailPath.moveTo(x, y);
  else trailPath.lineTo(x, y);
}
canvas.drawPath(trailPath, stroke('rgba(59,130,246,0.15)', 1));

