canvas.clear(CK.parseColorString('#fef2f2'));

const seismPath = new CK.Path();
const steps = 200;
for (let i = 0; i <= steps; i++) {
  const x = 40 + (i / steps) * 420;
  let y = 140;
  if (i > 60 && i < 140) {
    const t = (i - 60) / 80;
    y += Math.sin(t * Math.PI * 8) * 30 * Math.sin(t * Math.PI);
  }
  if (i === 0) seismPath.moveTo(x, y);
  else seismPath.lineTo(x, y);
}
canvas.drawPath(seismPath, stroke('#dc2626', 2.5));

