const p = ctx.currentFrame / ctx.sceneFrames;
const items = ['scene9-card1', 'scene9-card2', 'scene9-card3'];
const delays = [0.05, 0.2, 0.35];

for (let i = 0; i < items.length; i++) {
  const node = ctx.getNode(items[i]);
  const d = delays[i];
  const ease = Math.min((p - d) / 0.25, 1);
  const eased = ease < 0 ? 0 : ease > 1 ? 1 : 1 - Math.pow(1 - ease, 3);
  node.opacity(eased).translateY(20 * (1 - eased));
}

